{
  "name": "InsureClear Template Generator",
  "description": "An AI-powered tool that transforms complex insurance quotes into beautiful, easy-to-understand HTML templates for clients."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface CoverageItem {
  title: string;
  amount: string;
  explanation: string;
  example: string;
  color: 'blue' | 'green' | 'purple' | 'amber' | 'teal' | 'rose';
  icon: string;
}

export interface ExtraCoverage {
  name: string;
  description: string;
  cost: string;
  isIncluded: boolean;
  icon: string;
}

export interface DiscountItem {
  name: string;
}

export interface InsuranceData {
  customer: {
    name: string;
    address: string;
    quoteDate: string;
    policyPeriod: string;
  };
  carrier: {
    name: string;
    subText: string;
  };
  property: {
    type: string;
    built: string;
    construction: string;
    acreage: string;
    fireProtection: string;
    occupancy: string;
  };
  coverages: CoverageItem[];
  deductible: {
    amount: string;
    description: string;
  };
  extras: ExtraCoverage[];
  premium: {
    base: string;
    extrasCost: string;
    discountsAmount: string;
    totalAnnual: string;
    monthlyEstimate: string;
  };
  discounts: string[];
  agent: {
    name: string;
    address: string;
    phone: string;
    email: string;
    website: string;
  };
  notCovered: string; // Text summary of exclusions
}

export const INITIAL_DATA: InsuranceData = {
  customer: { name: 'Client Name', address: '123 Main St', quoteDate: 'Today', policyPeriod: '12 Months' },
  carrier: { name: 'Carrier Name', subText: 'Policy Type' },
  property: { type: '-', built: '-', construction: '-', acreage: '-', fireProtection: '-', occupancy: '-' },
  coverages: [],
  deductible: { amount: '$1,000', description: 'Standard Deductible' },
  extras: [],
  premium: { base: '$0', extrasCost: '$0', discountsAmount: '$0', totalAnnual: '$0', monthlyEstimate: '$0' },
  discounts: [],
  agent: { name: 'Agency Name', address: 'Address', phone: '555-555-5555', email: 'email@example.com', website: 'www.example.com' },
  notCovered: 'Standard exclusions apply.'
};

import { InsuranceData } from '../types';

export const generateInsuranceHtml = (data: InsuranceData): string => {
  const coveragesHtml = data.coverages.map(c => `
    <div class="coverage-card ${c.color}">
      <div class="card-header">
        <div class="card-title">${c.icon} ${c.title}</div>
        <div class="card-amount">${c.amount}</div>
      </div>
      <div class="card-explain">${c.explanation}</div>
      <div class="card-example"><strong>Example:</strong> ${c.example}</div>
    </div>
  `).join('');

  const extrasHtml = data.extras.map(e => `
    <tr>
      <td>
        <div class="extra-name">${e.icon} ${e.name}</div>
        <div class="extra-desc">${e.description}</div>
      </td>
      <td class="extra-cost">${e.isIncluded ? '<span class="included-badge">Included</span>' : e.cost}</td>
    </tr>
  `).join('');

  const discountsHtml = data.discounts.map(d => `<span class="discount-tag">${d}</span>`).join('');

  return `
<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Home Insurance Quote - ${data.customer.name}</title>
<link href="https://fonts.googleapis.com/css2?family=Merriweather:wght@400;700;900&family=Source+Sans+3:wght@400;600;700&display=swap" rel="stylesheet">
<style>
  @page { size: letter; margin: 0.5in 0.6in; }
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: 'Source Sans 3', sans-serif; color: #2d3748; font-size: 13px; line-height: 1.45; background: #fff; -webkit-print-color-adjust: exact; print-color-adjust: exact; }
  .page { width: 8.5in; min-height: 10in; margin: 0 auto; padding: 0.5in 0.6in; page-break-after: always; position: relative; }
  .page:last-child { page-break-after: auto; }

  /* HEADER */
  .header { display: flex; align-items: center; justify-content: space-between; padding-bottom: 14px; border-bottom: 3px solid #1a3a5c; margin-bottom: 18px; }
  .header-title h1 { font-family: 'Merriweather', serif; font-size: 20px; font-weight: 900; color: #1a3a5c; letter-spacing: -0.3px; }
  .header-title p { font-size: 11px; color: #64748b; margin-top: 2px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.8px; }
  .header-carrier { text-align: right; }
  .header-carrier .carrier-name { font-family: 'Merriweather', serif; font-size: 13px; font-weight: 700; color: #1a3a5c; }
  .header-carrier .carrier-sub { font-size: 10px; color: #94a3b8; margin-top: 1px; }

  /* CUSTOMER INFO */
  .customer-bar { background: linear-gradient(135deg, #f0f5fa 0%, #e8eff7 100%); border-radius: 8px; padding: 14px 18px; display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 18px; border: 1px solid #d4e0ed; }
  .customer-info h2 { font-family: 'Merriweather', serif; font-size: 16px; font-weight: 700; color: #1a3a5c; margin-bottom: 3px; }
  .customer-info .address { font-size: 12.5px; color: #475569; }
