import { GoogleGenAI, Type } from '@google/genai';
import { InsuranceData } from '../types';

export const parseInsuranceQuote = async (
  file: File,
  instructions: string
): Promise<InsuranceData> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error('API Key not found');

  const ai = new GoogleGenAI({ apiKey });

  // Convert File to Base64
  const base64Data = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data URL prefix (e.g., "data:application/pdf;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });

  const mimeType = file.type;

  const prompt = `
    You are an expert insurance marketing specialist. 
    Your goal is to extract data from this insurance quote document and formatted it into a clean, JSON structure suitable for a consumer-friendly marketing template.

    Specific Instructions from User: "${instructions}"

    Rules:
    1. Extract the customer name, address, carrier, and dates.
    2. Identify the property details (Year built, type, construction, etc). If missing, use "-".
    3. EXTRACT COVERAGES: Look for Dwelling, Other Structures, Personal Property, Loss of Use, Liability, and Medical Payments.
       - For each coverage, provide a SIMPLE explanation for a 5th grader.
       - Provide a REAL WORLD EXAMPLE of a claim for that coverage.
       - Assign a color (blue, green, purple, amber, teal, rose) and a related emoji icon.
    4. EXTRACT EXTRAS/ENDORSEMENTS: Look for line items like "Water Backup", "Service Line", "Equipment Breakdown", "Inland Flood".
       - If included in premium, mark isIncluded: true.
       - Provide a simple description of what it protects.
    5. EXTRACT PREMIUM: Base premium, discounts, total. Calculate a monthly estimate if not provided.
    6. AGENT INFO: If the document has agent info, use it. Otherwise use generic placeholders.
    7. NOT COVERED: Generate a standard summary of exclusions based on the policy type (usually HO-3).

    Return ONLY valid JSON matching the schema provided.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-latest',
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Data } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          customer: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              address: { type: Type.STRING },
              quoteDate: { type: Type.STRING },
              policyPeriod: { type: Type.STRING },
            }
