import React, { useState } from 'react';
import { Upload, FileText, Download, Wand2, AlertCircle } from 'lucide-react';
import { InsuranceData } from './types';
import { parseInsuranceQuote } from './services/geminiService';
import { generateInsuranceHtml } from './utils/htmlGenerator';
import PreviewTemplate from './components/PreviewTemplate';

const App: React.FC = () => {
  const [file, setFile] = useState<File | null>(null);
  const [instructions, setInstructions] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [data, setData] = useState<InsuranceData | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
      setError(null);
    }
  };

  const handleProcess = async () => {
    if (!file) {
      setError('Please upload a PDF or Image of the quote first.');
      return;
    }

    setIsProcessing(true);
    setError(null);

    try {
      const result = await parseInsuranceQuote(file, instructions);
      setData(result);
    } catch (err) {
      console.error(err);
      setError('Failed to process the document. Please ensure it is a valid quote and try again.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDownload = () => {
    if (!data) return;
    const html = generateInsuranceHtml(data);
    const blob = new Blob([html], { type: 'text/html' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Quote_Explanation_${data.customer.name.replace(/\s+/g, '_')}.html`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="min-h-screen bg-gray-50 text-gray-800 font-sans">
      {/* Navbar */}
      <nav className="bg-white border-b border-gray-200 sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between h-16 items-center">
            <div className="flex items-center gap-2">
              <div className="bg-blue-600 p-2 rounded-lg text-white">
                <FileText size={20} />
              </div>
              <span className="font-bold text-xl text-gray-900 tracking-tight">InsureClear</span>
            </div>
            <div className="text-sm text-gray-500">AI-Powered Proposal Generator</div>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-10">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          {/* LEFT COLUMN: Controls */}
          <div className="lg:col-span-4 space-y-6">

            <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
              <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                <Upload size={18} className="text-blue-600" />
                Upload Quote
              </h2>

              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Quote Document (PDF or Image)
                </label>
                <div className="relative border-2 border-dashed border-gray-300 rounded-lg p-6 hover:border-blue-400 transition-colors bg-gray-50 text-center">
                  <input
                    type="file"
                    accept=".pdf,image/*"
                    onChange={handleFileChange}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                  <div className="flex flex-col items-center">
                    {file ? (
                      <>
                        <FileText className="h-8 w-8 text-green-500 mb-2" />
                        <span className="text-sm font-medium text-gray-900 truncate max-w-xs">{file.name}</span>
                        <span className="text-xs text-gray-500 mt-1">{(file.size / 1024 / 1024).toFixed(2)} MB</span>
                      </>
                    ) : (
                      <>
                        <Upload className="h-8 w-8 text-gray-400 mb-2" />
                        <span className="text-sm text-gray-500">Click to upload or drag and drop</span>
                        <span className="text-xs text-gray-400 mt-1">PDF, PNG, JPG supported</span>
                      </>
                    )}
                  </div>
                </div>
              </div>

              <div className="mb-6">
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Instructions & Descriptions
                </label>
                <textarea
                  value={instructions}
                  onChange={(e) => setInstructions(e.target.value)}
                  placeholder="e.g., Emphasize the flood coverage, add a note about the roof age..."
                  className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 h-32 text-sm"
                />
              </div>

              <button
                onClick={handleProcess}
                disabled={isProcessing || !file}
                className={`w-full flex items-center justify-center gap-2 py-3 px-4 rounded-lg text-white font-medium transition-all ${
                  isProcessing || !file
                    ? 'bg-gray-300 cursor-not-allowed'
                    : 'bg-blue-600 hover:bg-blue-700 shadow-md hover:shadow-lg'
                }`}
              >
                {isProcessing ? (
                  <>
                    <div className="animate-spin rounded-full h-4 w-4 border-2 border-white border-t-transparent"></div>
                    Parsing Quote...
                  </>
                ) : (
                  <>
                    <Wand2 size={18} />
                    Generate Template
                  </>
                )}
              </button>

              {error && (
                <div className="mt-4 p-3 bg-red-50 text-red-700 text-sm rounded-lg flex items-start gap-2">
                  <AlertCircle size={16} className="mt-0.5 flex-shrink-0" />
                  {error}
                </div>
              )}
            </div>

            {data && (
               <div className="bg-green-50 p-6 rounded-xl border border-green-100 text-center">
                 <h3 className="text-green-800 font-semibold mb-2">Template Ready!</h3>
                 <p className="text-green-600 text-sm mb-4">Your file has been generated successfully.</p>
                 <button
                  onClick={handleDownload}
                  className="w-full flex items-center justify-center gap-2 py-3 px-4 bg-green-600 text-white rounded-lg font-medium hover:bg-green-700 shadow-sm transition-colors"
                 >
                   <Download size={18} />
                   Download HTML File
                 </button>
               </div>
            )}
          </div>

          {/* RIGHT COLUMN: Preview */}
          <div className="lg:col-span-8">
            <h2 className="text-xl font-bold text-gray-900 mb-4">Live Preview</h2>
            {data ? (
              <PreviewTemplate data={data} />
            ) : (
              <div className="border-2 border-dashed border-gray-200 rounded-xl h-[600px] flex flex-col items-center justify-center text-gray-400 bg-white">
                <FileText size={48} className="mb-4 opacity-20" />
                <p>Upload a quote to generate your preview</p>
              </div>
            )}
          </div>

        </div>
      </main>
    </div>
  );
};

