import { GoogleGenAI, Type } from '@google/genai';
import { InsuranceData, QuoteType } from '../types';

export const parseInsuranceQuote = async (
  file: File,
  instructions: string,
  quoteType: QuoteType
): Promise<InsuranceData> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error('API Key not found');

  const ai = new GoogleGenAI({ apiKey });

  // Convert File to Base64
  const base64Data = await new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => {
      const result = reader.result as string;
      // Remove data URL prefix
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });

  const mimeType = file.type;

  let typeSpecificPrompt = '';
  if (quoteType === 'home') {
    typeSpecificPrompt = `
      This is a HOME/PROPERTY insurance quote.
      - EXTRACT PROPERTY DETAILS: Year built, type, construction, acreage, fire protection class.
      - EXTRACT COVERAGES: Dwelling, Other Structures, Personal Property, Loss of Use, Liability, Med Pay.
      - GLOSSARY: Focus on terms like Replacement Cost, Dwelling, Deductible.
      - NOT COVERED: Standard HO-3 exclusions (Flood, Earth Movement, Wear & Tear).
    `;
  } else if (quoteType === 'auto') {
    typeSpecificPrompt = `
      This is an AUTO/VEHICLE insurance quote.
      - EXTRACT VEHICLES: Year, Make, Model, VIN (last 6 digits usually).
      - EXTRACT DRIVERS: Names and basic details (age or license status if avail).
      - EXTRACT COVERAGES: Bodily Injury, Property Damage, Comprehensive, Collision, Uninsured Motorist, PIP/MedPay.
      - GLOSSARY: Focus on Collision, Comprehensive, Liability, Deductible.
      - NOT COVERED: Standard Auto exclusions (Rideshare without endorsement, Racing, Intentional Acts).
    `;
  } else {
    typeSpecificPrompt = `
      This is a GENERAL/OTHER insurance quote (e.g. Umbrella, Commercial, Event).
      - EXTRACT SUBJECT: What is being insured? (Business name, specific item, or event).
      - EXTRACT COVERAGES: General Liability, Aggregate Limits, Specific Item limits.
      - GLOSSARY: General insurance terms relevant to the policy.
      - NOT COVERED: Standard exclusions for this policy type.
    `;
  }

  const prompt = `
    You are an expert insurance marketing specialist. 
    Your goal is to extract data from this insurance quote document and format it into a clean, JSON structure suitable for a consumer-friendly marketing template.

    QUOTE TYPE: ${quoteType.toUpperCase()}
    Specific Instructions from User: "${instructions}"

    ${typeSpecificPrompt}

    General Rules:
    1. Extract customer name, address, carrier, and dates.
    2. For Coverages: Provide a SIMPLE explanation for a 5th grader and a REAL WORLD EXAMPLE. Assign a color (blue, green, purple, amber, teal, rose) and an emoji icon.
    3. For Extras/Endorsements: If included in premium, mark isIncluded: true.
    4. For Premium: Extract base, discounts, total. Calculate monthly if missing.
    5. Agent Info: Extract or use placeholders.

    Return ONLY valid JSON matching the schema provided.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Data } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: 'application/json',
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          type: { type: Type.STRING, enum: ['home', 'auto', 'other'] },
          customer: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              address: { type: Type.STRING },
              quoteDate: { type: Type.STRING },
              policyPeriod: { type: Type.STRING },
            }
          },
          carrier: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              subText: { type: Type.STRING },
            }
          },
          // Home specific
          property: {
            type: Type.OBJECT,
            properties: {
              type: { type: Type.STRING },
              built: { type: Type.STRING },
              construction: { type: Type.STRING },
              acreage: { type: Type.STRING },
              fireProtection: { type: Type.STRING },
              occupancy: { type: Type.STRING },
            },
            nullable: true
          },
          // Auto specific
          vehicles: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                year: { type: Type.STRING },
                make: { type: Type.STRING },
                model: { type: Type.STRING },
                vin: { type: Type.STRING },
              }
            },
            nullable: true
          },
          drivers: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                details: { type: Type.STRING },
              }
            },
            nullable: true
          },
          // Other specific
          subject: { type: Type.STRING, nullable: true },

          coverages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                amount: { type: Type.STRING },
                explanation: { type: Type.STRING },
                example: { type: Type.STRING },
                color: { type: Type.STRING, enum: ['blue', 'green', 'purple', 'amber', 'teal', 'rose'] },
                icon: { type: Type.STRING },
              }
            }
          },
          deductible: {
            type: Type.OBJECT,
            properties: {
              amount: { type: Type.STRING },
              description: { type: Type.STRING },
            }
          },
          extras: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                description: { type: Type.STRING },
                cost: { type: Type.STRING },
                isIncluded: { type: Type.BOOLEAN },
                icon: { type: Type.STRING },
              }
            }
          },
          premium: {
            type: Type.OBJECT,
            properties: {
              base: { type: Type.STRING },
              extrasCost: { type: Type.STRING },
              discountsAmount: { type: Type.STRING },
              totalAnnual: { type: Type.STRING },
              monthlyEstimate: { type: Type.STRING },
            }
          },
          discounts: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          },
          agent: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              address: { type: Type.STRING },
              phone: { type: Type.STRING },
              email: { type: Type.STRING },
              website: { type: Type.STRING },
            }
          },
          notCovered: { type: Type.STRING }
        }
      }
    }
  });

  const text = response.text;
  if (!text) throw new Error('No response from AI');

  return JSON.parse(text) as InsuranceData;
};

