      <td>${p.planName} ${idx === 0 ? '<span class="pay-badge">Recommended</span>' : ''}</td>
      <td>${p.downPayment}</td>
      <td>${p.installments || `x ${p.monthlyAmount}/mo`}</td>
    </tr>
  `).join('') || '';

  const discountsHtml = data.discounts.map(d => `<span class="discount-tag">${d}</span>`).join('');

  return `
