export const generateInsuranceHtml = (data: InsuranceData): string => {
  if (data.type === 'auto') {
    return generateAutoHtml(data);
  } else {
    // Default to Home/Generic template
    return generateHomeHtml(data);
  }
};

export type QuoteType = 'home' | 'auto' | 'other' | 'home-hero';

export interface CoverageItem {
  title: string;
  amount: string;
  explanation: string;
  example: string;
  color: 'blue' | 'green' | 'purple' | 'amber' | 'teal' | 'rose';
  icon: string;
}

export interface ExtraCoverage {
  name: string;
  description: string;
  cost: string;
  isIncluded: boolean;
  icon: string;
}

export interface DiscountItem {
  name: string;
}

export interface VehicleCoverage {
  name: string;
  limit?: string;
  deductible?: string;
  premium?: string;
  included?: boolean;
  icon?: string;
}

export interface Vehicle {
  year: string;
  make: string;
  model: string;
  vin: string;
  usage?: string;
  zip?: string;
  annualPremium?: string;
  coverages?: VehicleCoverage[];
}

export interface Driver {
  name: string;
  details: string; // "Age 61 • Male..."
  isRated?: boolean;
}

export interface PaymentOption {
  planName: string;
  downPayment: string;
  monthlyAmount: string;
  installments?: string; // "11 x $128.09"
}

export interface InsuranceData {
  type: QuoteType;
  homePhotoUrl?: string; // For Home + Hero template
  customer: {
    name: string;
    address: string;
    quoteDate: string;
    policyPeriod: string;
  };
  carrier: {
    name: string;
    subText: string;
  };
  // Specific to Home
  property?: {
    type: string;
    built: string;
    construction: string;
    acreage: string;
    fireProtection: string;
    occupancy: string;
  };
  // Specific to Auto
  vehicles?: Vehicle[];
  drivers?: Driver[];
  // Specific to Other
  subject?: string; 

  coverages: CoverageItem[]; // Core/Policy-wide coverages
  deductible: {
    amount: string;
    description: string;
  };
  extras: ExtraCoverage[];
  premium: {
    base: string;
    extrasCost: string;
    discountsAmount: string;
    totalAnnual: string;
    monthlyEstimate: string;
  };
  paymentOptions?: PaymentOption[];
  discounts: string[];
  agent: {
    name: string;
    address: string;
    phone: string;
    email: string;
    website: string;
    logoUrl?: string;
  };
  notCovered: string; 
}

